pub struct Bm25Config {
    /// BM25 k1 parameter. Default: 1.2.
    #[serde(default = "default_bm25_k1")]
    pub k1: f32,
    /// BM25 b parameter. Default: 0.75.
    #[serde(default = "default_bm25_b")]
    pub b: f32,
}
impl Default for Bm25Config {
    fn default() -> Self {
        Self {
            k1: default_bm25_k1(),
            b: default_bm25_b(),
        }
    }
}
